selector_to_html = {"a[href=\"https://en.wikipedia.org/wiki/Unscented_transform\"]": "<p>The <b>unscented transform</b> (UT) is a mathematical function used to estimate the result of applying a given nonlinear transformation to a probability distribution that is characterized only in terms of a finite set of statistics. The most common use of the unscented transform is in the nonlinear projection of mean and covariance estimates in the context of nonlinear extensions of the Kalman filter. Its creator Jeffrey Uhlmann explained that \"unscented\" was an arbitrary name that he adopted to avoid it being referred to as the \u201cUhlmann filter.\u201d</p>", "a[href^=\"https://en.wikipedia.org/wiki/Unscented_transform#\"]": "<p>The <b>unscented transform</b> (UT) is a mathematical function used to estimate the result of applying a given nonlinear transformation to a probability distribution that is characterized only in terms of a finite set of statistics. The most common use of the unscented transform is in the nonlinear projection of mean and covariance estimates in the context of nonlinear extensions of the Kalman filter. Its creator Jeffrey Uhlmann explained that \"unscented\" was an arbitrary name that he adopted to avoid it being referred to as the \u201cUhlmann filter.\u201d</p>", "a[href=\"https://en.wikipedia.org/wiki/Inverse-variance_weighting\"]": "<p>In statistics, <b>inverse-variance weighting</b> is a method of aggregating two or more random variables to minimize the variance of the weighted average. Each random variable is weighted in inverse proportion to its variance.</p>", "a[href^=\"https://en.wikipedia.org/wiki/Inverse-variance_weighting#\"]": "<p>In statistics, <b>inverse-variance weighting</b> is a method of aggregating two or more random variables to minimize the variance of the weighted average. Each random variable is weighted in inverse proportion to its variance.</p>", "a[href=\"https://en.wikipedia.org/wiki/Chebyshev%E2%80%93Gauss_quadrature\"]": "<p>In numerical analysis <b>Chebyshev\u2013Gauss quadrature</b> is an extension of Gaussian quadrature method for approximating the value of integrals of the following kind:</p><dl><dd><span class=\"mwe-math-element mwe-math-element-inline\"><img src=\"https://wikimedia.org/api/rest_v1/media/math/render/svg/5e7801d5b29dff44b2032d2aec530f18fea07d08\" class=\"mwe-math-fallback-image-inline mw-invert skin-invert\" aria-hidden=\"true\" style=\"vertical-align:-3.171ex;width:17.663ex;height:7.009ex\" /></span></dd></dl>", "a[href^=\"https://en.wikipedia.org/wiki/Chebyshev%E2%80%93Gauss_quadrature#\"]": "<p>In numerical analysis <b>Chebyshev\u2013Gauss quadrature</b> is an extension of Gaussian quadrature method for approximating the value of integrals of the following kind:</p><dl><dd><span class=\"mwe-math-element mwe-math-element-inline\"><img src=\"https://wikimedia.org/api/rest_v1/media/math/render/svg/5e7801d5b29dff44b2032d2aec530f18fea07d08\" class=\"mwe-math-fallback-image-inline mw-invert skin-invert\" aria-hidden=\"true\" style=\"vertical-align:-3.171ex;width:17.663ex;height:7.009ex\" /></span></dd></dl>", "a[href=\"#point-grid\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">3-Point Grid<a class=\"headerlink\" href=\"#point-grid\" title=\"Link to this heading\">\u00b6</a></h2><p>The module <code class=\"docutils literal notranslate\"><span class=\"pre\">stacie.dq</span></code> also includes a simple function <a class=\"reference internal\" href=\"../apidocs/stacie.dq.html#stacie.dq.dq3\" title=\"stacie.dq.dq3\"><code class=\"xref py py-func docutils literal notranslate\"><span class=\"pre\">stacie.dq.dq3()</span></code></a>\nto construct a 3-point quadrature grid with equal weights.\nThe grid will integrate exactly any degree-3 polynomial times a distribution\nwith given mean, standard deviation and skewness.\nNote that real solutions for the points only exist for skewness values in the range\n<span class=\"math notranslate nohighlight\">\\(\\left[-\\frac{1}{\\sqrt{2}}, \\frac{1}{\\sqrt{2}}\\right]\\)</span>.</p><p>A simple example:</p>", "a[href=\"#implementation\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Implementation<a class=\"headerlink\" href=\"#implementation\" title=\"Link to this heading\">\u00b6</a></h2><p>Note that the deviations between the first two quadrature methods and the true value\nare not due to noise, but rather due to the fact that\nthe quadrature rules are approximate for a non-polynomial integrand.</p><p>The approximate DQ method and Monte Carlo are affected by sampling noise:</p>", "a[href=\"#comparison-of-quadrature-methods\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Comparison of Quadrature Methods<a class=\"headerlink\" href=\"#comparison-of-quadrature-methods\" title=\"Link to this heading\">\u00b6</a></h2><p>We will compare four quadrature methods:</p>", "a[href=\"../apidocs/stacie.dq.html#stacie.dq.dq3\"]": "<dt class=\"sig sig-object py\" id=\"stacie.dq.dq3\">\n<span class=\"sig-name descname\"><span class=\"pre\">dq3</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">mean</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">std</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">skew</span></span></em><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"../_modules/stacie/dq.html#dq3\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Construct a 3-point quadrature grid to integrate degree-3 polynomials exactly.</p><p>The results are exact for an integral of a degree-3 polynomial times\na distribution with the given mean, standard deviation and skewness.</p></dd>", "a[href=\"#test-case-with-a-noisy-integrand\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Test Case With a Noisy Integrand<a class=\"headerlink\" href=\"#test-case-with-a-noisy-integrand\" title=\"Link to this heading\">\u00b6</a></h2><p>This notebook demonstrates the DQ method with a computationally cheap but noisy integrand.\nIn practice, the integrand is typically (very) expensive to evaluate,\nand the noise arises from the sampling required to estimate the integrand at each point.</p><p>We will use a noisy cosine function as example integrand,\nand the standard normal distribution as probability density function:</p>", "a[href=\"../apidocs/stacie.dq.html#module-stacie.dq\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">stacie.dq module<a class=\"headerlink\" href=\"#module-stacie.dq\" title=\"Link to this heading\">\u00b6</a></h1><p>Designed Quadrature (DQ).</p><p>This DQ implementation assumes fixed quadrature weights, by default equal weights\nas in Chebyshev quadrature, but the user can specify any positive weights.\nUnlike standard Gaussian quadrature, the integration grids are optimal for noisy integrands,\nfor which the main source of error is the variance of the integrand rather than the\nlimited polynomial degree of the quadrature.\nThis is achieved by optimizing the grid point positions assuming equal (or fixed) weights.\nEqual weights minimize the variance of the numerical integral when all function values on the grid\nhave independent and identically distributed noise.\nUnlike Monte Carlo integration, the integration grid is deterministic and guarantees\na certain level of polynomial degree for smooth integrands.\nThe main contribution of this module is to provide a practical and efficient implementation\nfor the optimization of the grid points.\nIt only supports 1D grids.\nThis module also offers a few additional features that may come in handy for practical applications:</p>", "a[href=\"#designed-quadrature-dq\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Designed Quadrature (DQ)<a class=\"headerlink\" href=\"#designed-quadrature-dq\" title=\"Link to this heading\">\u00b6</a></h1><p>(This feature will become available with STACIE 1.3.0,\nwhich is not yet released at the time of writing.)</p><p>This notebook illustrates how to use the module <a class=\"reference internal\" href=\"../apidocs/stacie.dq.html#module-stacie.dq\" title=\"stacie.dq\"><code class=\"xref py py-mod docutils literal notranslate\"><span class=\"pre\">stacie.dq</span></code></a> to compute\nintegrals over noisy integrands.\nWhile solving this problem is not the main goal of STACIE,\nit is often a useful step when post-processing transport properties\ncomputed with STACIE at different densities and/or total energies.</p>", "a[href=\"#designed-quadrature-with-unequal-weights\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Designed Quadrature with Unequal Weights<a class=\"headerlink\" href=\"#designed-quadrature-with-unequal-weights\" title=\"Link to this heading\">\u00b6</a></h2><p>As mentioned above, it is also possible dial in a specific choice of quadrature weights,\nup to a normalization factor, during the optimization of the quadrature points.\nThis can be useful to obtain simpler grids with the same polynomial exactness.\nThe code below illustrates how this can be accomplished.</p><p>We\u2019ll use Gauss-Hermite points and weights as a source of inspiration:</p>", "a[href=\"#regression-tests\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Regression Tests<a class=\"headerlink\" href=\"#regression-tests\" title=\"Link to this heading\">\u00b6</a></h2><p>If you are experimenting with this notebook, you can ignore any exceptions below.\nThe tests are only meant to pass for the notebook in its original form.</p>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(` ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false,

            });
        };
    };
    console.log("tippy tips loaded!");
};
